SELECT id, user_id, user_name, user_room, payment_type, payment_amount, payment_status, payment_no, payment_time, overdue_amount, due_time, create_by, create_time, update_by, update_time, remark
FROM community_payment
WHERE user_id = #{userId}
  AND user_name LIKE CONCAT('%', #{userName}, '%')
  AND user_room = #{userRoom}
  AND payment_type = #{paymentType}
  AND payment_amount = #{paymentAmount}
  AND payment_status = #{paymentStatus}
  AND payment_no = #{paymentNo}
  AND payment_time = #{paymentTime}
  AND overdue_amount = #{overdueAmount}
  AND due_time = #{dueTime}

SELECT id, user_id, user_name, user_room, payment_type, payment_amount, payment_status, payment_no, payment_time, overdue_amount, due_time, create_by, create_time, update_by, update_time, remark
FROM community_payment
WHERE id = #{id}
